package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	"github.com/google/uuid"
	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
)

type presignRequest struct {
	Filename    string `json:"filename"`
	ContentType string `json:"contentType"`
}

type presignResponse struct {
	URL string `json:"url"`
	Key string `json:"key"`
}

type errorResponse struct {
	Error string `json:"error"`
}

func writeJSON(w http.ResponseWriter, status int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(v)
}

func main() {
	app := pocketbase.New()

	app.OnBeforeServe().Add(func(e *core.ServeEvent) error {
		e.Router.POST("/api/presign-upload", func(re *core.RequestEvent) error {
			return presignUploadHandler(re)
		})
		return nil
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

func presignUploadHandler(re *core.RequestEvent) error {
	var req presignRequest
	if err := json.NewDecoder(re.Request.Body).Decode(&req); err != nil {
		writeJSON(re.Response, http.StatusBadRequest, errorResponse{Error: "invalid request body"})
		return nil
	}

	if req.Filename == "" {
		writeJSON(re.Response, http.StatusBadRequest, errorResponse{Error: "filename is required"})
		return nil
	}
	if req.ContentType == "" {
		writeJSON(re.Response, http.StatusBadRequest, errorResponse{Error: "contentType is required"})
		return nil
	}

	endpoint := os.Getenv("S3_ENDPOINT")
	region := os.Getenv("S3_REGION")
	bucket := os.Getenv("S3_BUCKET")
	accessKey := os.Getenv("S3_ACCESS_KEY")
	secretKey := os.Getenv("S3_SECRET_KEY")

	if endpoint == "" || region == "" || bucket == "" || accessKey == "" || secretKey == "" {
		writeJSON(re.Response, http.StatusInternalServerError, errorResponse{
			Error: "S3 configuration is incomplete; check environment variables",
		})
		return nil
	}

	// Generate a unique object key preserving the original file extension.
	ext := filepath.Ext(req.Filename)
	key := uuid.New().String() + ext

	cfg, err := config.LoadDefaultConfig(context.Background(),
		config.WithRegion(region),
		config.WithCredentialsProvider(credentials.NewStaticCredentialsProvider(accessKey, secretKey, "")),
	)
	if err != nil {
		log.Printf("failed to load AWS config: %v", err)
		writeJSON(re.Response, http.StatusInternalServerError, errorResponse{Error: "failed to configure S3 client"})
		return nil
	}

	s3Client := s3.NewFromConfig(cfg, func(o *s3.Options) {
		o.BaseEndpoint = aws.String(endpoint)
		o.UsePathStyle = true
	})

	presignClient := s3.NewPresignClient(s3Client)

	presignedReq, err := presignClient.PresignPutObject(context.Background(), &s3.PutObjectInput{
		Bucket:      aws.String(bucket),
		Key:         aws.String(key),
		ContentType: aws.String(req.ContentType),
	}, func(opts *s3.PresignOptions) {
		opts.Expires = 15 * time.Minute
	})
	if err != nil {
		log.Printf("failed to presign URL: %v", err)
		writeJSON(re.Response, http.StatusInternalServerError, errorResponse{Error: "failed to generate presigned URL"})
		return nil
	}

	writeJSON(re.Response, http.StatusOK, presignResponse{
		URL: presignedReq.URL,
		Key: key,
	})
	return nil
}

